proof fn phi_1_execution_equality_intensional_bridge(ex1: Execution<int>, ex2: Execution<int>)
    requires
        forall |i: nat| #[trigger] (ex1.nat_to_state)(i) == (ex2.nat_to_state)(i),
    ensures
        ex1 == ex2,
{
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_2_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.implies(q).satisfied_by(ex),
        p.satisfied_by(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_3_stable_unfold_closure_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        stable(p).satisfied_by(ex),
        p.satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    stable_unfold::<int>(ex, p);
}

proof fn phi_4_leads_to_unfold_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>, i: nat)
    requires
        p.leads_to(q).satisfied_by(ex),
    ensures
        p.implies(eventually(q)).satisfied_by(ex.suffix(i)),
{
    leads_to_unfold::<int>(ex, p, q);
}

proof fn phi_5_suffix_zero_equals_self(ex: Execution<int>)
    ensures
        ex.suffix(0) == ex,
{
    assert forall |i: nat| #[trigger] (ex.suffix(0).nat_to_state)(i) == (ex.nat_to_state)(i) by {};
    execution_equality::<int>(ex.suffix(0), ex);
}
